#include <numeric>

#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    int solve(int n) {
        if (n == 0) return 1;
        int rightmost_unset = n & -n;
        int rightmost_set = (n ^ (n - 1)) & n;
        if (rightmost_unset == rightmost_set) return n;
        return n | rightmost_unset ^ rightmost_set;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int _;
    if (!(cin >> _)) return 0;
    int n;
    if (!(cin >> n)) return 0;
    Solution sol;
    int ans = sol.solve(n);
    cout << 1 << endl;
    cout << ans << endl;
    return 0;
}
